class Fibonacci:
    """A Fibonacci sequence that supports indexing (including negative indices)."""

    def __init__(self):
        self._cache = []  # stores generated Fibonacci numbers: F(0), F(1), ...

    def _generate_up_to(self, n: int):
        """Ensure the cache contains at least n+1 elements (indices 0..n)."""
        while len(self._cache) <= n:
            if len(self._cache) == 0:
                self._cache.append(0)          # F(0) = 0
            elif len(self._cache) == 1:
                self._cache.append(1)          # F(1) = 1
            else:
                next_val = self._cache[-1] + self._cache[-2]
                self._cache.append(next_val)

    def __getitem__(self, index):
        if not isinstance(index, int):
            raise TypeError("Index must be an integer")
        # Handle negative indices based on current cache length
        if index < 0:
            pos = len(self._cache) + index
            if pos < 0:
                raise IndexError(
                    f"Negative index {index} out of range (cache length {len(self._cache)})"
                )
        else:
            pos = index
        # Ensure we have enough elements
        self._generate_up_to(pos)
        return self._cache[pos]

    def __len__(self):
        return len(self._cache)

    def __repr__(self):
        return f"Fibonacci({self._cache})"
